#!/bin/bash\n\n# ============================================\n# HEROKU DEPLOYMENT SCRIPT FOR N8N REVENUE SYSTEM\n# ============================================\n\necho \"🚀 N8N Revenue System - Heroku Deployment\"\necho \"==========================================\"\necho \"\"\n\n# Check if Heroku CLI is installed\nif ! command -v heroku &> /dev/null; then\n    echo \"❌ Heroku CLI not found. Install it from: https://devcenter.heroku.com/articles/heroku-cli\"\n    exit 1\nfi\n\necho \"✅ Heroku CLI found\"\necho \"\"\n\n# Get app name from user\nread -p \"Enter your Heroku app name (e.g., n8n-revenue-system): \" APP_NAME\n\nif [ -z \"$APP_NAME\" ]; then\n    echo \"❌ App name cannot be empty\"\n    exit 1\nfi\n\necho \"\"\necho \"📋 Deployment Steps:\"\necho \"-------------------------------------------\"\necho \"\"\n\n# 1. Create Heroku app\necho \"1️⃣  Creating Heroku app...\"\nheroku create $APP_NAME --buildpack=heroku/docker\n\nif [ $? -ne 0 ]; then\n    echo \"❌ Failed to create app. Checking if it already exists...\"\n    heroku apps:info $APP_NAME\nelse\n    echo \"✅ App created successfully\"\nfi\n\necho \"\"\necho \"2️⃣  Adding PostgreSQL database...\"\nheroku addons:create heroku-postgresql:standard-0 --app=$APP_NAME\necho \"✅ PostgreSQL added\"\n\necho \"\"\necho \"3️⃣  Configuring environment variables...\"\necho \"Setting up N8N environment...\"\n\nheroku config:set N8N_HOST=$APP_NAME.herokuapp.com --app=$APP_NAME\nheroku config:set N8N_PROTOCOL=https --app=$APP_NAME\nheroku config:set N8N_PORT=8080 --app=$APP_NAME\nheroku config:set N8N_WEBHOOK_TUNNEL_URL=https://$APP_NAME.herokuapp.com --app=$APP_NAME\nheroku config:set JWT_SECRET=$(openssl rand -base64 32) --app=$APP_NAME\nheroku config:set DB_TYPE=postgresdb --app=$APP_NAME\n\necho \"✅ Environment configured\"\n\necho \"\"\necho \"4️⃣  Deploying application...\"\necho \"Pushing code to Heroku...\"\ngit push heroku main\n\nif [ $? -ne 0 ]; then\n    echo \"❌ Deployment failed. Check git remote:\"\n    git remote -v\n    exit 1\nfi\n\necho \"✅ Deployment complete!\"\n\necho \"\"\necho \"===========================================\"\necho \"🎉 DEPLOYMENT SUCCESSFUL!\"\necho \"===========================================\"\necho \"\"\necho \"Your N8N Revenue System is now live!\"\necho \"\"\necho \"📍 Access Points:\"\necho \"   N8N Editor: https://$APP_NAME.herokuapp.com\"\necho \"   Database:   Managed by Heroku Postgres\"\necho \"\"\necho \"🔧 Useful Commands:\"\necho \"   View logs:     heroku logs --app=$APP_NAME -f\"\necho \"   Stop app:      heroku dyos:stop --app=$APP_NAME\"\necho \"   Scale workers: heroku ps:scale worker=1 --app=$APP_NAME\"\necho \"   Reset DB:      heroku pg:reset DATABASE --app=$APP_NAME\"\necho \"\"\necho \"💡 Next Steps:\"\necho \"   1. Go to https://$APP_NAME.herokuapp.com\"\necho \"   2. Set up your API integrations (HubSpot, SendGrid, etc.)\"\necho \"   3. Import workflows\"\necho \"   4. Configure webhooks for your forms\"\necho \"\"\necho \"📚 Documentation: https://docs.n8n.io/\"\necho \"\"\n"
